#!/usr/bin/env python3
"""还原 interview.db 数据库（从 base64 解码）"""
import base64, os, zipfile, io

B64 = """"""

def restore():
    target = os.path.join(os.path.dirname(__file__), "..", "interview.db")
    # Decode base64 -> zip -> extract
    raw = base64.b64decode(B64)
    with zipfile.ZipFile(io.BytesIO(raw)) as z:
        z.extractall(os.path.dirname(target))
    size = os.path.getsize(target)
    print(f"✅ interview.db 已还原 ({size/1024:.0f}KB)")

if __name__ == "__main__":
    restore()
